  ('elementary-8b44517b-moex-00071', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '在雇主有歇業、清算或宣告破產之情事時，關於工資優先受償權及工資墊償基金之敘述，何者正確？', '["對於本於勞動契約所積欠之工資未滿 6 個月部分，勞工之受償順序劣於第一順位抵押權、質權或留置 權所擔保之債權", "雇主未依勞動基準法或勞工退休金條例給付之資遣費，經勞工請求未獲清償時，在 6 個月平均工資之 範圍內，由積欠工資墊償基金墊償", "雇主之工資墊償基金，由中央主管機關於萬分之十範圍內擬訂", "積欠工資墊償基金之收繳有關業務，得由中央主管機關，委託各地方政府勞動局辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00072', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列關於勞動基準法第84條之1之工作時間規制除外適用規定的敘述，何者錯誤？', '["適用的對象限於經中央主管機關核定公告之特定工作人員", "應報請當地主管機關核備", "雇主可使適用本條規定之勞工連續工作5小時而不需休息", "適用本條規定之勞工，其工作時間應由勞雇雙方另行約定，但仍應參考勞動基準法所定之基準且不得損 及勞工之健康及福祉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00073', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '採取何種變形工時制度時，勞工的每日正常工作時間為8小時？', '["2週變形工時", "4週變形工時", "8週變形工時", "所有變形工時之每日正常工作時間均為8小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00074', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '輪班制工作更換班次時，至少應有連續X小時之休息時間。但因工作特性或特殊原因，經中央目的事業 主管機關商請中央主管機關公告者，得變更休息時間不少於連續Y小時。請問上述的X與Y各為何？', '["X為12，Y為7", "X為11，Y為7", "X為12，Y為8", "X為11，Y為8"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00075', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '雇主延長勞工之工作時間1個月不得超過X小時，但雇主經工會同意，如事業單位無工會者，經勞資會 議同意後，延長之工作時間，1個月不得超過54小時，每3個月不得超過Y小時。請問上述的X與Y各 為何？', '["X為50，Y為138", "X為46，Y為138", "X為50，Y為150", "X為46，Y為150"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00076', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '要派單位於派遣事業單位與派遣勞工簽訂勞動契約前，面試該派遣勞工或其他指定特定派遣勞工時，其法 律效果為何？', '["該派遣勞工之雇主仍為派遣事業單位", "若要派單位已受領派遣勞工勞務，該派遣勞工得於要派單位提供勞務之日起90日內，以書面向要派單 位提出訂定勞動契約之意思表示", "該派遣勞工之雇主應即轉換為要派單位", "不生任何影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
